#include <bits/stdc++.h>
using namespace std;
int n,a=1,b=1,mark[10004][10004];
int main(){
    cin>>n;
    mark[1][1]=1;
    for(int i=2;i<=n;i++){
        if(i==2){
            b++;
            mark[a][b]=1;
            continue;
        }
        if(b>1 && !mark[a+1][b-1])a++,b--;
        else if(a>1 && !mark[a-1][b+1])a--,b++;
        else if(b==1 && mark[a-1][b+1])a++;
        else b++;
        mark[a][b]=1;
    }
    cout<<a<<'/'<<b;
    return 0;
}
